function fixRightColumnTop() {
    // if SBP return
    if ($(window).width() < 769) {
        columnRight.style.top = null;
    } else {
        if (columnRight) {
            columnRight.style.top = $(window).height() - columnRight.scrollHeight - 10 + 'px';
        } else {
            setTimeout(function () {
                columnRight = $('.column-right')[0];
                fixRightColumnTop();
            }, 500);
        }
    }
}
