        referrerPolicy: "no-referrer-when-downgrade"
    }).then(function (res) {
        if (res.ok) {
            res.json().then(function (e) {
                if (e.status) {
                    qexoInner("qexo-site-uv", e.site_uv);
                    qexoInner("qexo-site-pv", e.site_pv);
                    qexoInner("qexo-page-pv", e.page_pv);
                } else {
                    console.log(e.error);
                    qexoFailed()
                }
            })
        } else {
            qexoFailed()
        }
    }, function (ex) {
        console.log('站点统计失败! 网络错误')
